import javafx.xml.*; // this line contains XML parsing functionality using standard library 'javax' 
// and also SAX parser (Simple API for XML) which will be used to parse an XML document in chunks from a source, instead of reading the entire file into memory at once or feeding it directly through DOM Parser. It provides more flexibility than JDOM / DocumentBuilder etc., but still requires external libraries
// To use SAX parser we need third-party library 'sax'  for Java (https://xmlgraphics.apache.org/sax/) . For simple parsing only standard java is enough, no extra dependencies required like jdom or xmlbeans.  
import org.xml.sax.*; //SAX Parser Interface in Oracle JDK version of XML APIs provide SAX parser which allows us to parse an document stream and then feed it into a handler via the event-driven style approach without loading all data at once (with Memory-mapped files or InputStream etc.)
import org.xml.sax.helpers.*; //SAX helper classes for easier usage of sax parsing, which include DocumentHandlerImpl – this class java_47878_XMLParser_A01 used to handle events in an SAX way and can be shared among multiple documents as well using the EventSource interface from javax package (not necessary with Java Standard Edition)
import java.net.*;//to use URLConnection object for accessing web content or reading xml data like http://www.java2s.com/Code/Java/Networking-HTTPSClientExample39701586#sample_url and https: //stackoverflow.com /questions ​​​/// Java - Connect to a URL via HTTP
import java.io.*;//for reading xml data using InputStream or BufferedReader (not necessary with standard libraries) like http://www .java2s . com/Code-Detail?id=19347680 for more details and https: //stackoverflow ​/// Java - Reading from URL
